import{a2 as n,a3 as s,ao as t}from"./index.37c25fac.js";var p="/posts/image-20220319212215367.png",e="/posts/image-20220319212513260.png",o="/posts/image-20220319212941961.png",i="/posts/image-20220319212315831.png",r="/posts/image-20220319213207916.png",l="/posts/image-20220319213412728.png",c="/posts/image-20220319214751930.png",u="/posts/image-20220319215151766.png",g="/posts/image-20220319220158821.png";const m={class:"md-blog m-auto text-left"},d=t('<h1 id="%E6%95%B0%E7%94%B5%E8%AE%A1%E7%BB%84%E5%AE%9E%E9%AA%8C-vscode-%E9%85%8D%E7%BD%AE%E6%8C%87%E5%8D%97" tabindex="-1">\u6570\u7535\u8BA1\u7EC4\u5B9E\u9A8C Vscode \u914D\u7F6E\u6307\u5357</h1><p>\u672C\u7BC7\u535A\u5BA2\u5C06\u5E26\u6765\u4F18\u96C5\u7684 Vscode \u7F16\u5199\u6570\u5B57\u7535\u8DEF\u5B9E\u9A8C / \u8BA1\u7B97\u673A\u7EC4\u6210\u539F\u7406\u5B9E\u9A8C\u7684 Verilog \u4E00\u952E\u5F0F\u914D\u7F6E\u65B9\u6848\uFF0C\u8BA9\u4F60\u7F16\u5199\u4EE3\u7801\u5168\u7A0B\u8FDC\u79BB Vivado \uFF08<s>\u65B0\u5EFA\u5DE5\u7A0B\u8FD8\u662F\u8981\u89C1\u4E00\u9762\u7684</s>\uFF09</p><p>\u4E3B\u8981\u8FD8\u662F\u4ECB\u7ECD\u4E00\u4E9B\u540D\u8BCD\u548C\u5DE5\u5177\uFF0C\u8BFB\u8005\u770B\u4E0A\u53BB\u4E86\u54EA\u4E9B\u53EF\u4EE5\u81EA\u5DF1\u6311</p><p><img src="'+p+'" alt="image-20220319212215367"></p><h2 id="vscode-%E6%8F%92%E4%BB%B6" tabindex="-1">Vscode \u63D2\u4EF6</h2><p>\u9996\u5148\u53EF\u80FD\u9700\u8981\u8FDE\u63A5\u8FDC\u7A0B\u7684 Vlab \u670D\u52A1\u5668\uFF0C\u8FD9\u4E2A\u65F6\u5019\u9700\u8981\u4F7F\u7528 Vscode-remote \u63D2\u4EF6</p><p><img src="'+e+'" alt="image-20220319212513260"></p><p>\u8FD9\u4E2A\u63D2\u4EF6\u4E3B\u8981\u4F5C\u7528\u5C31\u662F\u80FD\u5728\u672C\u5730\u901A\u8FC7 SSH \u8FDE\u63A5\u64CD\u4F5C Vlab \u865A\u62DF\u673A</p><p>\u5177\u4F53\u914D\u7F6E\u8FC7\u7A0B\u4E0D\u518D\u8D58\u8FF0\uFF0C\u914D\u7F6E\u5B8C\u4E4B\u540E\u53EF\u4EE5\u5F88\u65B9\u4FBF\u7684\u6D4F\u89C8\u8FDC\u7A0B\u6587\u4EF6</p><p><img src="'+o+'" alt="image-20220319212941961"></p><p>\u8FD9\u4E2A\u65F6\u5019\u5DF2\u7ECF\u80FD\u6109\u5FEB\u7684\u5728 Vscode \u4E0A\u5199 Verilog \u4E86\uFF0C\u4F46\u662F\u4EC5\u4EC5\u80FD\u5199\u80AF\u5B9A\u4E0D\u591F\uFF0C\u6211\u4EEC\u8FD8\u9700\u8981\u4E00\u4E2A linter(\u68C0\u67E5\u8BED\u6CD5) \u8FD8\u6709\u4E00\u4E2A formatter(\u4EE3\u7801\u683C\u5F0F\u5316)</p><p>\u8FD9\u91CC\u63A8\u8350\u4E00\u4E2A\u63D2\u4EF6\uFF1ADigital IDE</p><p><img src="'+i+'" alt="image-20220319212315831"></p><p>\u63D2\u4EF6\u6765\u81EA <a href="https://github.com/ysy-phoenix">ysy-phoenix</a> \u7684\u63A8\u8350\uFF0C\u5728\u6B64\u611F\u8C22</p><p>\u914D\u7F6E\u5B8C\u4E4B\u540E\u5E94\u8BE5\u5DF2\u7ECF\u9ED8\u8BA4\u6709\u4EE3\u7801\u683C\u5F0F\u5316\u548C\u7AEF\u53E3\u7684\u5404\u79CD\u63D0\u793A\u4FE1\u606F\u4E86\uFF0C\u4E0A\u56FE\u7684\u4EE3\u7801\u5C31\u662F\u8FD9\u4E2A\u63D2\u4EF6\u683C\u5F0F\u540E\u7684\u6210\u679C</p><p>\u4F46 linter \u8FD8\u9700\u8981\u989D\u5916\u914D\u7F6E\uFF0C\u8FD9\u91CC\u6211\u4EEC\u6253\u5F00\u63D2\u4EF6\u7684\u8BBE\u7F6E\uFF1A</p><p><img src="'+r+`" alt="image-20220319213207916"></p><p>\u4E2A\u4EBA\u611F\u89C9 verilator \u66F4\u597D\u7528\uFF0C\u5F53\u7136 Vlab \u865A\u62DF\u673A\u4E0A\u9ED8\u8BA4\u662F\u6CA1\u6709\u81EA\u5E26\u7684\uFF0C\u4E0D\u8FC7 ubuntu \u901A\u8FC7\u5305\u7BA1\u7406\u5668\u5B89\u88C5\u8FD8\u662F\u5F88\u65B9\u4FBF\u7684\uFF1A</p><pre class="language-bash"><code class="language-bash"><span class="token function">apt</span> update				// \u8FD9\u4E00\u6B65\u4E3A\u4E86\u786E\u4FDD\u8F6F\u4EF6\u5305\u662F\u6700\u65B0\u7684
<span class="token function">apt</span> <span class="token function">install</span> verilator	// \u5B89\u88C5
</code></pre><p>\u4E24\u4E0B\u5C31\u597D\u4E86\uFF0C\u4E4B\u540E\u5199\u4EE3\u7801\u65F6\u4E00\u4FDD\u5B58\u6587\u4EF6\u5C31\u53EF\u4EE5\u81EA\u52A8\u5E2E\u4F60\u68C0\u67E5\u8BED\u6CD5\u9519\u8BEF\u4E86\uFF1A</p><p><img src="`+l+'" alt="image-20220319213412728"></p><p>\uFF08\u8FD9\u91CC\u62A5\u9519\u4F1A\u663E\u793A\u5728\u4E00\u884C\u4E0A\u662F\u56E0\u4E3A\u88C5\u4E86\u53E6\u4E00\u4E2A\u63D2\u4EF6 Error Lens\uFF0C\u5F88\u7F8E\u89C2\uFF0C\u4EB2\u6D4B\u597D\u7528\uFF09</p><h2 id="%E5%B9%B2%E6%8E%89-vivado-%E4%B9%8B%E4%BB%BF%E7%9C%9F%E7%AF%87" tabindex="-1">\u5E72\u6389 Vivado \u4E4B\u4EFF\u771F\u7BC7</h2><p>\u4EFF\u771F\u9700\u8981\u770B\u6CE2\u5F62\uFF0C\u8FD9\u4E2A\u65F6\u5019\u4E00\u4E2A\u63A8\u8350\u662F <code>gtkwave</code>\uFF0Cubuntu \u4E0B\u540C\u6837\u901A\u8FC7\u5305\u7BA1\u7406\u5668\u5B89\u88C5\u5373\u53EF</p><p>\u56E0\u4E3A\u8FD9\u4E2A\u4E0D\u80FD\u5728\u6CA1\u6709\u56FE\u5F62\u754C\u9762\u7684 Vlab \u4E0A\u8FD0\u884C\uFF0C\u6240\u4EE5\u4E0B\u6587\u7ED9\u51FA\u7684\u4EFF\u771F\u63A8\u8350\u90FD\u662F\u914D\u5728\u672C\u5730\u73AF\u5883\u7684\uFF1A</p><h3 id="icarus-verilog" tabindex="-1">Icarus Verilog</h3><p>\u5927\u540D\u9F0E\u9F0E\u7684\u4E00\u4E2A\u4EFF\u771F\u5DE5\u5177\uFF0C\u7B80\u79F0 iverilog, \u5982\u679C\u4F60\u7528 ubuntu \u7684\u5305\u7BA1\u7406\u5668\u88C5\u5B83\u8FD8\u4F1A\u81EA\u52A8\u5E2E\u4F60\u88C5\u4E0A gtkwave\uFF08<s>\u6346\u7ED1\u6D88\u8D39</s>\uFF09</p><p>Digital IDE \u81EA\u5E26\u4E86\u5BF9\u4E8E Icarus Verilog \u7684\u5FEB\u901F\u4EFF\u771F\u652F\u6301\uFF0C\u89C1 <a href="https://zhuanlan.zhihu.com/p/365805011">\u5B83\u7684\u6587\u6863</a></p><h3 id="verilator" tabindex="-1">Verilator</h3><p>\u8FD9\u91CC\u8FD8\u662F\u8981\u5B89\u5229 Verilator\uFF0C\u56E0\u4E3A\u7528\u5B83\u505A\u4EFF\u771F\u53EF\u4EE5 <strong>\u4E0D\u5199 Verilog</strong> \uFF0CVerilator \u4F1A\u751F\u6210\u9AD8\u5C42\u6B21\u7684 C++ \u4EE3\u7801\u6A21\u62DF\u6A21\u5757\u7684\u884C\u4E3A\uFF0C\u7136\u540E\u4F60\u53EA\u9700\u8981\u7528 C++ \u7F16\u5199 top \u6A21\u5757\u8FDB\u884C\u6D4B\u8BD5\u5C31\u884C\u4E86</p><p>\u5F88\u5927\u7684\u597D\u5904\u5728\u4E8E C++ \u4F5C\u4E3A\u9AD8\u7EA7\u8BED\u8A00\u5F88\u660E\u663E\u6BD4 Verilog \u7684 testbench \u5199\u8D77\u6765\u7075\u6D3B</p><p>ubuntu \u5305\u7BA1\u7406\u5668\u88C5\u7684\u7248\u672C\u6BD4\u8F83\u65E7\uFF0C\u5982\u679C\u60F3\u8981\u6700\u65B0\u7248\u53EF\u4EE5\u81EA\u5DF1\u4E0B\u8F7D\u5B83\u7684 github \u4ED3\u5E93\u6309\u7167\u8BF4\u660E\u7F16\u8BD1\uFF0C\u4E0D\u8FC7\u8FD9\u6837\u5C31\u9EBB\u70E6\u4E00\u70B9\u4E86</p><p>\u5177\u4F53\u4F7F\u7528\u65B9\u5F0F\u53EF\u4EE5\u53C2\u8003 <a href="http://www.sunnychen.top/2019/07/25/%E8%B7%A8%E8%AF%AD%E8%A8%80%E7%9A%84Verilator%E4%BB%BF%E7%9C%9F%EF%BC%9A%E4%BD%BF%E7%94%A8%E8%BF%9B%E7%A8%8B%E9%97%B4%E9%80%9A%E4%BF%A1/">\u8FD9\u7BC7\u6587\u7AE0</a> \uFF0C<s>\u5BF9\u7740\u590D\u5236\u7C98\u8D34\u5C31\u884C</s></p><p>\u5982\u679C\u4F60\u53D1\u73B0 Vscode \u627E\u4E0D\u5230\u5934\u6587\u4EF6 <code>verilated.h</code> \uFF0C\u90A3\u5C31\u627E\u5230\u8FD9\u4E2A\u8BBE\u7F6E\uFF08\u76F4\u63A5\u5728 Vscode \u7684\u8BBE\u7F6E\u91CC\u641C\u7D22\u5373\u53EF\uFF09\uFF0C\u8DEF\u5F84\u6DFB\u52A0\u4EE5\u4E0B\u4E24\u4E2A\u4E2D\u7684\u4E00\u4E2A\uFF08\u6839\u636E\u4F60\u81EA\u5DF1\u7684\u60C5\u51B5\u800C\u5B9A\uFF0C\u81EA\u5DF1\u770B\u54EA\u4E2A\u76EE\u5F55\u80FD\u8FDB\uFF0C\u5982\u679C\u662F\u5305\u7BA1\u7406\u5668\u88C5\u7684\u5E94\u8BE5\u662F\u4E0B\u9762\u90A3\u4E2A\u8DEF\u5F84\uFF09</p><p><img src="'+c+'" alt="image-20220319214751930"></p><p>\u7136\u540E\u5C31\u53EF\u4EE5\u6109\u60A6\u7684\u7F16\u5199 C++ \u4EE3\u7801\u4EFF\u771F\u4E86\uFF0C\u4EE5\u4E0B\u662F\u4E00\u4E2A\u5BF9 ALU \u6A21\u5757 100% \u8986\u76D6\u7387\u7684\u6D4B\u8BD5\u793A\u4F8B\uFF1A</p><p><img src="'+u+`" alt="image-20220319215151766"></p><p>\u6839\u636E\u4E0A\u9762\u90A3\u7BC7\u94FE\u63A5\u91CC\u6559\u7A0B\u7684\u6B65\u9AA4\uFF0C\u5373\u53EF\u5224\u65AD\u4EFF\u771F\u7ED3\u679C\u662F\u5426\u6B63\u786E\uFF0C\u5E76\u751F\u6210\u6CE2\u5F62</p><h2 id="%E5%B9%B2%E6%8E%89-vivado-%E4%B9%8B%E6%AF%94%E7%89%B9%E6%B5%81" tabindex="-1">\u5E72\u6389 Vivado \u4E4B\u6BD4\u7279\u6D41</h2><p>\u5199\u5B8C\u4EE3\u7801\u6211\u4EEC\u8FD8\u9700\u8981 Vivado \u8FD9\u4E2A<s>\u5DE5\u5177\u4EBA</s>\u5E2E\u6211\u4EEC\u751F\u6210\u6BD4\u7279\u6D41</p><p>\u4F46\u6BCF\u6B21\u6253\u5F00 VNC \u64CD\u4F5C Vivado \u663E\u7136\u592A\u8FC7\u7B28\u91CD\uFF0C\u8FD9\u4E2A\u65F6\u5019\u6211\u4EEC\u53EF\u4EE5\u5229\u7528 Vivado \u81EA\u5E26\u7684 TCL \u547D\u4EE4\u884C\u5DE5\u5177\u6765\u6784\u5EFA\u9879\u76EE</p><p>\u8FD9\u91CC\u76F4\u63A5\u8D34\u4E00\u4E2A Vlab \u80FD\u7528\u7684\u811A\u672C\uFF08\u5982\u679C\u5728\u672C\u5730\u8DD1\u53EF\u80FD\u9700\u8981\u4E00\u4E9B\u4FEE\u6539\uFF09<a href="https://github.com/WuTianming">\u4F5C\u8005\u94FE\u63A5</a></p><pre class="language-bash"><code class="language-bash"><span class="token shebang important">#!/bin/bash</span>

<span class="token builtin class-name">echo</span> <span class="token string">&quot;Initiating project build ...&quot;</span>

<span class="token assign-left variable">ProjName</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$(</span><span class="token function">find</span> <span class="token builtin class-name">.</span> -type f -iname <span class="token string">&quot;*.xpr&quot;</span><span class="token variable">)</span></span>
<span class="token keyword">if</span> <span class="token punctuation">[</span> -z <span class="token string">&quot;<span class="token variable">$ProjName</span>&quot;</span> <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span>
    <span class="token builtin class-name">echo</span> <span class="token string">&quot;xpr file not found. Exiting&quot;</span>
    <span class="token builtin class-name">exit</span> <span class="token number">1</span>
<span class="token keyword">fi</span>
<span class="token builtin class-name">echo</span> <span class="token string">&quot;Found project file <span class="token variable">\${ProjName}</span>.&quot;</span>

<span class="token builtin class-name">echo</span> <span class="token string">&quot;Creating build script ...&quot;</span>
<span class="token function">cat</span> - <span class="token operator">&gt;</span> automation_genbitstream.tcl <span class="token operator">&lt;&lt;</span> <span class="token string">EOF
set_param general.maxThreads 2
open_project <span class="token variable">\${ProjName}</span>

reset_run synth_1
launch_run synth_1
wait_on_run synth_1
open_run synth_1
# report_timing_summary
launch_run -to_step write_bitstream impl_1
wait_on_run impl_1
# open_run impl_1
# report_timing_summary
# report_utilization &gt; utilization.txt

quit
EOF</span>

<span class="token function">cat</span> - <span class="token operator">&gt;</span> wrapper.tcl <span class="token operator">&lt;&lt;</span> <span class="token string">EOF
if {[catch {source automation_genbitstream.tcl} errorstring]} {
    puts &quot;Error - <span class="token variable">$errorstring</span>&quot;
    exit 1
}
quit
EOF</span>

<span class="token function">cat</span> - <span class="token operator">&gt;</span> build_remote.sh <span class="token operator">&lt;&lt;</span> <span class="token string">EOF
#!/bin/bash

# source /extra/vivado2016/Vivado/2016.3/settings64.sh
source /opt/vlab/path.sh

if ! time vivado2019 -mode tcl -source wrapper.tcl; then
	grep --color=always &quot;ERROR&quot; vivado.log
fi
rm -f *.log *.jou
printf &quot;<span class="token entity" title="\\a">\\a</span>&quot;
EOF</span>

<span class="token builtin class-name">echo</span> <span class="token string">&quot;Running job ...&quot;</span>
<span class="token function">bash</span> build_remote.sh
<span class="token builtin class-name">echo</span> <span class="token string">&quot;Build done.&quot;</span>

<span class="token function">rm</span> automation_genbitstream.tcl wrapper.tcl build_remote.sh
</code></pre><p>\u653E\u5728\u548C xpr \u6587\u4EF6\u540C\u4E00\u4E2A\u76EE\u5F55\uFF08\u4E5F\u5C31\u662F\u9879\u76EE\u76EE\u5F55\u4E0B\u5373\u53EF\uFF09</p><p>\u600E\u4E48\u8FD0\u884C\u811A\u672C\u8FD9\u91CC\u4E0D\u518D\u8D58\u8FF0</p><p><img src="`+g+'" alt="image-20220319220158821"></p><p>\u53EF\u4EE5\u5F88\u6F02\u4EAE\u7684\u5728\u547D\u4EE4\u884C\u91CC\u5F97\u5230\u7ED3\u679C\u5E76\u770B\u5230\u5404\u79CD report</p><p>\u5177\u4F53\u8BBE\u7F6E\u53EF\u4EE5\u81EA\u5DF1\u770B\u811A\u672C\u88AB\u6CE8\u91CA\u6389\u7684\u4E00\u4E9B\u90E8\u5206</p><p>\u81F3\u6B64\u6211\u4EEC\u6210\u529F\u6784\u5EFA\u4E86\u4E00\u5957\u8FD8\u7B97\u8D81\u624B\u7684 Verilog \u5F00\u53D1\u5DE5\u5177\u94FE</p>',49),h=[d],B={setup(_,{expose:a}){return a({frontmatter:{}}),(b,E)=>(n(),s("div",m,h))}};export{B as default};
